import{r as e,o as a,c as d,a as i,w as l,F as c,b as o,d as r}from"./app.2e1eaa90.js";const s={},h=i("h1",{id:"数据管理",tabindex:"-1"},[i("a",{class:"header-anchor",href:"#数据管理","aria-hidden":"true"},"#"),o(" 数据管理")],-1),n={class:"custom-container tip"},t=i("p",{class:"custom-container-title"},"TIP",-1),u=o("本章中介绍的内容需要你安装数据库支持，同时建议提前阅读 "),p=o("指南 · 用户系统管理"),g=o("。"),f=r('<h2 id="基础功能" tabindex="-1"><a class="header-anchor" href="#基础功能" aria-hidden="true">#</a> 基础功能</h2><h3 id="指令-callme" tabindex="-1"><a class="header-anchor" href="#指令-callme" aria-hidden="true">#</a> 指令：callme</h3><ul><li>基本语法：<code>callme [name]</code></li></ul><p>callme 指令用于修改用户的昵称。如果不传入参数，则机器人会返回你当前的昵称。重复的昵称、空昵称和含有消息段的昵称是不被接受的。</p><h3 id="指令-bind" tabindex="-1"><a class="header-anchor" href="#指令-bind" aria-hidden="true">#</a> 指令：bind</h3><ul><li>基本语法：<code>bind</code></li><li>最低权限：0</li></ul><p>bind 指令用于跨平台绑定账号。该指令 0 级权限即可调用。</p><p>如果此指令在私聊环境下被调用，则 Koishi 会生成一串随机码。你只需在 5 分钟内使用你的其他账号在要绑定的平台内向机器人发送这串随机码，即可完成绑定。</p><p>如果此指令在群聊环境下被调用，由于此时生成的随机码是公开的，你需要首先按照上述流程发送一次随机码。接着，收到并核验过随机码的机器人将再向你发送一串新的随机码。你仍需要在 5 分钟内使用你一开始的账号在之前的平台内向机器人发送这串随机码，即可完成绑定。</p><h3 id="指令-authorize" tabindex="-1"><a class="header-anchor" href="#指令-authorize" aria-hidden="true">#</a> 指令：authorize</h3><ul><li>别名：auth</li><li>基本语法：<code>authorize -t &lt;user&gt; &lt;authority&gt;</code></li><li>最低权限：4</li></ul><p>authorize 指令用于设置用户的权限等级。该指令 4 级权限才能调用，且需要满足目标用户的权限和要设定的权限都严格小于自己的权限等级，否则无法设置。</p><h3 id="指令-assign" tabindex="-1"><a class="header-anchor" href="#指令-assign" aria-hidden="true">#</a> 指令：assign</h3><ul><li>基本语法：<code>assign -t [channel] [assignee]</code></li><li>最低权限：4</li></ul>',14),m=o("assign 指令可用于设置频道的 "),x=o("代理者"),b=o("。该指令 4 级权限才能调用。"),B=r('<p>如果 <code>-t [channel]</code> 缺省，则表示目标频道为当前频道（因此私聊状态下不能缺省）；如果 <code>assignee</code> 缺省，则表示当前接收消息的机器人账号。举个例子，如果要设定一个频道 A 的代理者为 B，下面的两种做法是等价的：</p><ol><li>私聊机器人 B，发送 <code>assign -t #A</code></li><li>在频道 A 中发送 <code>@B assign</code>（假设 B 能收到此消息）</li></ol><h2 id="高级用法" tabindex="-1"><a class="header-anchor" href="#高级用法" aria-hidden="true">#</a> 高级用法</h2><p>所有本节中介绍的指令都是指令 user 和 channel 的子指令，且它们都拥有下面的基本选项：</p><ul><li><code>-t, --target [@user|#channel]</code> 目标用户 / 频道（需要 3 级权限）</li></ul><p>与上一节介绍的两个指令类似，当这个选项缺省时，默认的目标都是当前用户或当前频道。</p><h3 id="指令-user-usage" tabindex="-1"><a class="header-anchor" href="#指令-user-usage" aria-hidden="true">#</a> 指令：user.usage</h3><h3 id="指令-user-timer" tabindex="-1"><a class="header-anchor" href="#指令-user-timer" aria-hidden="true">#</a> 指令：user.timer</h3><ul><li>基本语法：<code>user.xxx [key] [value]</code></li><li>选项： <ul><li><code>-s, --set</code> 设置访问记录（需要 4 级权限）</li><li><code>-c, --clear</code> 清除访问记录（需要 4 级权限）</li></ul></li></ul>',9),E=o("这两个指令用于查看和修改用户的访问记录，参见 "),A=o("指令调用管理"),k=o("。"),y=r('<p>如果不提供 <code>-s</code> 和 <code>-c</code> 选项，则会显示当前的访问记录。如果使用了 <code>-s</code>，就会设置名为 <code>key</code> 的访问记录为 <code>value</code>。如果使用了 <code>-c</code> 且提供了 <code>key</code>，就会清除名为 <code>key</code> 的访问记录；否则会清除所有的访问记录。</p><h3 id="指令-user-flag" tabindex="-1"><a class="header-anchor" href="#指令-user-flag" aria-hidden="true">#</a> 指令：user.flag</h3><h3 id="指令-channel-flag" tabindex="-1"><a class="header-anchor" href="#指令-channel-flag" aria-hidden="true">#</a> 指令：channel.flag</h3><ul><li>基本语法：<code>xxx.flag [...names]</code></li><li>选项： <ul><li><code>-l, --list</code> 标记列表</li><li><code>-s, --set</code> 添加标记（需要 4 级权限）</li><li><code>-S, --unset</code> 删除标记（需要 4 级权限）</li></ul></li></ul><p>这两个指令用于查看和修改用户或频道的状态标签。如果不提供选项，则会显示当前的状态标签。如果使用了 <code>-l</code>，就会列出所有可用的状态标签。如果使用了 <code>-s</code> 或 <code>-S</code>，则会添加 / 删除 <code>names</code> 中的每一个状态标签。</p>',5);s.render=function(o,r){const s=e("RouterLink");return a(),d(c,null,[h,i("div",n,[t,i("p",null,[u,i(s,{to:"/guide/manage.html"},{default:l((()=>[p])),_:1}),g])]),f,i("p",null,[m,i(s,{to:"/guide/manage.html#%E5%B9%B3%E5%8F%B0%E7%9B%B8%E5%85%B3%E5%AD%97%E6%AE%B5"},{default:l((()=>[x])),_:1}),b]),B,i("p",null,[E,i(s,{to:"/guide/manage.html#%E6%8C%87%E4%BB%A4%E8%B0%83%E7%94%A8%E7%AE%A1%E7%90%86"},{default:l((()=>[A])),_:1}),k]),y],64)};export default s;
